import React, { useState, useEffect } from 'react';
import './App.css';
import Topo from "./componentes/TopoOferta";
import Rodape from "./componentes/Rodape";
import { buscarOfertasPromocao } from "./componentes/ofertasService";

function App() {
  const [produtos, setProdutos] = useState([]);
  const [carrinho, setCarrinho] = useState([]);
  const [etapa, setEtapa] = useState('vitrine');
  const [modoCadastro, setModoCadastro] = useState(false);
  const [usuario, setUsuario] = useState(() => {
    const salvo = localStorage.getItem('usuario_logado');
    return salvo ? JSON.parse(salvo) : null;
  });
  const [formaPagamento, setFormaPagamento] = useState('');
  const [pedidoFinalizado, setPedidoFinalizado] = useState(null);
  const [historico, setHistorico] = useState([]);
  const [origemLogin, setOrigemLogin] = useState('checkout');
  const [formData, setFormData] = useState({ nome: '', email: '', senha: '', telefone: '', cep: '', endereco: '', cpf: '' });

  useEffect(() => {
    const carregarDadosIniciais = async () => {
      try {
        const res = await fetch("http://localhost:3001/produtos");
        const dados = await res.json();
        setProdutos(dados);
      } catch (err) {
        console.error("Erro ao carregar vitrine inicial:", err);
      }
    };
    carregarDadosIniciais();
  }, []);

  // --- FUNÇÕES AUXILIARES ---
  const fazerLogout = () => {
    localStorage.removeItem('usuario_logado');
    setUsuario(null);
    setEtapa('vitrine');
    window.location.reload();
  };

  const adicionarAoCarrinho = (p) => {
    const itemExiste = carrinho.find(item => item.id === p.id);
    if (itemExiste) {
      setCarrinho(carrinho.map(item => item.id === p.id ? { ...item, qtd: item.qtd + 1 } : item));
    } else {
      setCarrinho([...carrinho, { ...p, qtd: 1 }]);
    }
  };

  const alterarQuantidade = (id, delta) => {
    setCarrinho(carrinho.map(item => {
      if (item.id === id) {
        const novaQtd = item.qtd + delta;
        return novaQtd > 0 ? { ...item, qtd: novaQtd } : item;
      }
      return item;
    }).filter(item => item.qtd > 0));
  };

  const removerDoCarrinho = (id) => {
    setCarrinho(carrinho.filter(item => item.id !== id));
  };

  const obterPrecoPromocional = (produto) => {
    const campos = [
      'Desconto_10porct',
      'desconto_10porct',
      'valor_promocional',
      'valorPromocional',
      'preco_promocional',
      'precoPromocional',
      'valor_oferta',
      'preco_oferta'
    ];

    for (const campo of campos) {
      if (produto[campo] !== undefined && produto[campo] !== null && produto[campo] !== '') {
        return produto[campo];
      }
    }

    return null;
  };

  const precoEfetivoProduto = (produto) => {
    const promocional = obterPrecoPromocional(produto);
    return promocional !== null && promocional !== undefined && promocional !== ''
      ? parseFloat(promocional)
      : parseFloat(produto.valor || produto.preco || 0);
  };

  const totalProd = carrinho.reduce((acc, i) => {
    return acc + (precoEfetivoProduto(i) * i.qtd);
  }, 0);

  const valorFrete = formaPagamento === 'pix' ? 0 : 15.00;

  // --- MÉTODOS DE AUTENTICAÇÃO E HISTÓRICO ---
  const handleAuth = async () => {
    const rota = modoCadastro ? 'cadastrar' : 'login';
    try {
      const response = await fetch(`http://localhost:3001/${rota}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(formData)
      });
      const dados = await response.json();

      if (response.ok) {
        setUsuario(dados);
        localStorage.setItem('usuario_logado', JSON.stringify(dados));
        if (origemLogin === 'historico') {
          const idParaBusca = dados.id_cliente || dados.id;
          const resH = await fetch(`http://localhost:3001/historico/${idParaBusca}`);
          const dadosH = await resH.json();
          setHistorico(Array.isArray(dadosH) ? dadosH : []);
          setEtapa('historico');
        } else {
          setEtapa('checkout');
        }
      } else {
        alert(dados.message || "Erro na autenticação");
      }
    } catch (err) {
      alert("Erro de conexão.");
    }
  };

  const carregarHistorico = () => {
    // 1. Limpa o utilizador para forçar novo login
    localStorage.removeItem('usuario_logado');
    setUsuario(null);
    // 2. Prepara o caminho para o login pedir e-mail/senha
    setOrigemLogin('historico');
    setEtapa('login');
  };

  const carregarOfertas = async () => {
    const ofertas = await buscarOfertasPromocao();
    if (ofertas.length > 0) {
      setProdutos(ofertas);
      setEtapa('vitrine');
    } else {
      alert("Nenhuma oferta encontrada.");
    }
  };

  const finalizar = async () => {
    const userAtual = usuario || JSON.parse(localStorage.getItem('usuario_logado'));
    if (!userAtual) return setEtapa('login');
    const novoNumeroPedido = Math.floor(Math.random() * 100000);
    try {
      for (const item of carrinho) {
        const valorVenda = item.Desconto_10porct ? item.Desconto_10porct : item.valor;
        await fetch("http://localhost:3001/venda_cliente", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            id_pedido: novoNumeroPedido,
            id_cliente: userAtual.id || userAtual.id_cliente,
            produto: item.produto,
            quantidade: item.qtd || 1,
            valor: valorVenda,
            id_produto: item.id
          })
        });
      }
      setPedidoFinalizado({ numero: novoNumeroPedido });
      setEtapa('sucesso');
      setCarrinho([]);
    } catch (err) {
      alert("Falha no Pedido: " + err.message);
    }
  };

  return (
    <div className="App">
      <Topo 
        totalItens={carrinho.length} 
        abrirCarrinho={() => setEtapa('carrinho')} 
        verHistorico={carregarHistorico} 
        usuarioLogado={usuario} 
        onLogout={fazerLogout}
        verOfertas={carregarOfertas}
      />
      
      <main className="conteudo-principal">
        {etapa === 'vitrine' && (
          <div className="container-vitrine">
            {produtos.some(p => p.Desconto_10porct) && (
              <div className="barra-topo-ofertas">
                <button className="btn-voltar-inicial" onClick={() => window.location.reload()}>🏠 Início</button>
                <h2 className="titulo-ofertas">🔥 Ofertas Ativas</h2>
              </div>
            )}
            <div className="grid-produtos">
              {produtos.map((p) => {
                const precoPromocional = p.Desconto_10porct ?? p.desconto_10porct ?? p.valor_promocional ?? null;
                const temOferta = precoPromocional !== null && precoPromocional !== undefined && precoPromocional !== '';
                const precoAntigo = parseFloat(p.valor || p.Valor_antigo || 0).toFixed(2);
                return (
                  <div key={p.id} className="card">
                    {temOferta && <div className="badge-promo">10% OFF</div>}

                    <img src={p.imagem_url || p.foto} alt={p.produto} />
                    <h3>{p.produto}</h3>

                    <div className="preco-container">
                      {temOferta ? (
                        <div className="preco-promocional">
                          <div>
                            <span className="texto-label-promocao">De: </span>
                            <span className="preco-antigo">R$ {precoAntigo}</span>
                          </div>
                          <div>
                            <span className="texto-label-promocao">Por: </span>
                            <span className="preco-novo">R$ {parseFloat(precoPromocional).toFixed(2)}</span>
                          </div>
                        </div>
                      ) : (
                        <span className="preco-normal">R$ {parseFloat(p.valor || 0).toFixed(2)}</span>
                      )}
                    </div>

                    {/* Botão de compra com a classe correta */}
                    <button className="btn-comprar" onClick={() => adicionarAoCarrinho(p)}>
                      🛒 Comprar
                    </button>
                  </div>
                );
              })}
            </div>
          </div>
        )}
        {etapa === 'carrinho' && (
          <div className="container-venda">
            <h2>🛒 Carrinho</h2>
            <button className="btn-voltar-inicial" onClick={() => window.location.reload()}>🏠 Início</button>
            {carrinho.length === 0 ? (
              <button onClick={() => setEtapa('vitrine')}>🏠 Voltar</button>
            ) : (
              <>
                {carrinho.map(i => (
                  <div key={i.id} className="item-carrinho-detalhado">
                    <span>{i.produto} (x{i.qtd})</span>
                    <button onClick={() => removerDoCarrinho(i.id)}>🗑️</button>
                  </div>
                ))}
                <h3>Total: R$ {totalProd.toFixed(2)}</h3>
                <button className="btn-p" onClick={() => setEtapa('login')}>Finalizar</button>
              </>
            )}
          </div>
        )}

        {etapa === 'login' && (
          <div className="container-venda">
            <h2>{modoCadastro ? "📝 Cadastro" : "🔐 Login"}</h2>
            <input className="in-v" placeholder="E-mail" onChange={e => setFormData({...formData, email: e.target.value})} />
            <input className="in-v" type="password" placeholder="Senha" onChange={e => setFormData({...formData, senha: e.target.value})} />
            <button className="btn-p" onClick={handleAuth}>{modoCadastro ? "Cadastrar" : "Entrar"}</button>
            <p onClick={() => setModoCadastro(!modoCadastro)} style={{cursor:'pointer'}}>Trocar para {modoCadastro ? "Login" : "Cadastro"}</p>
            {origemLogin === 'historico' && (
              <button className="btn-voltar-inicial" onClick={() => setEtapa('vitrine')}>
                🏠 Início
              </button>
            )}
          </div>
        )}

        {etapa === 'historico' && (
          <div className="container-venda">
            <h2>📋 Meus Pedidos</h2>
            {historico.map((ped, idx) => (
              <div key={idx} style={{borderBottom: '1px solid #ccc', padding: '10px'}}>
                <p>Pedido #{ped.numero_pedido} - {ped.itens_do_pedido}</p>
                <p>Total: R$ {parseFloat(ped.valor_total_pedido).toFixed(2)}</p>
              </div>
            ))}
            <button className="btn-voltar-inicial" onClick={() => setEtapa('vitrine')}>🏠 Início</button>
          </div>
        )}

        {etapa === 'checkout' && (
           <div className="container-venda">
             <h2>📍 Entrega para {usuario?.nome}</h2>
             <select className="in-v" onChange={e => setFormaPagamento(e.target.value)}>
               <option value="">Pagamento...</option>
               <option value="pix">Pix</option>
               <option value="cartao">Cartão</option>
             </select>
             <button className="btn-p" onClick={finalizar}>Confirmar Pedido</button>
           </div>
        )}

        {etapa === 'sucesso' && (
          <div className="alerta-s">
            <h2>✅ Pedido Confirmado!</h2>
            <button className="btn-p" onClick={() => setEtapa('vitrine')}>Voltar</button>
          </div>
        )}
      </main>
      <Rodape />
    </div>
  );
}

export default App;
